package com.ibm.demo.day1.fundas;

public class ControlStructureDemo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int m = 3;
		switch (m) {
		case 1: {
			System.out.println("1 is crct");
			break;
		}
		case 2: {
			System.out.println("2 is crct");
			break;
		}
		case 3: {
			System.out.println("3 is crct");
			break;
		}
		default: {
			System.out.println("none is crct");
			break;
		}

		}
	}

}
